      | `RequestLimitExceeded -> "RequestLimitExceeded"
      | `ServiceUnavailable -> "ServiceUnavailable"
      | `Unavailable -> "Unavailable"
      | `Unknown_code s -> s
    let to_json ((code, message) : t) : Yojson.Safe.t=
      `Assoc (("code", (`String (code_to_string code))) ::
        (match message with
         | None -> []
         | Some m -> [("message", (`String m))]))
    let of_xml =
      function
      | `Data _ as xml ->
          failwithf "Ec2_error.of_xml: expected element, got data: %s"
            (Awso.Xml.to_string xml) ()
      | `El (((_, name), _), _) as xml ->
          (match name with
           | "Response" ->
               let data =
                 function
                 | `Data s -> s
                 | `El (_, children) ->
                     (List.map children
                        ~f:(function | `Data s -> s | `El _ -> ""))
                       |> (String.concat ~sep:"") in
               let _request_id = data (Awso.Xml.child_exn xml "RequestID") in
               let errors =
                 ((Awso.Xml.child_exn xml "Errors") |> Awso.Xml.all_children)
                   |>
                   (List.map
                      ~f:(fun error ->
                            let code =
                              (Awso.Xml.child_exn error "Code") |> data in
                            let message =
                              (Awso.Xml.child_exn error "Message") |> data in
                            ((string_to_code code), (Some message)))) in
               (match errors with
                | [] ->
                    failwithf
                      "Ec2_error.of_xml: no errors in Ec2 error response" ()
                | error::[] -> error
                | _lst ->
                    failwithf
                      "Ec2_error.of_xml: multiple errors not supported" ())
           | name ->
               failwithf "Ec2_error: expected 'Response' tag got '%s': %s"
                 name (Awso.Xml.to_string xml) ())
  end
let simple_to_json to_value x =
  Botodata.Json.value_to_json_scalar (to_value x)
let composed_to_json to_value x = Botodata.Json.value_to_json (to_value x)
let to_query to_value x = Client.Query.of_value (to_value x)
let structure_to_value_aux st ~f =
  let filter = function | (k, Some v) -> Some (k, v) | _ -> None in
  let pair k v = (k, v) in
  let defer_value (k, dv) = pair k dv in
  ((List.filter_map st ~f:filter) |> (List.map ~f:defer_value)) |>
    (fun x -> `Structure (f x))
let structure_to_value = structure_to_value_aux ~f:Fn.id
let structure_to_wrapped_value ~wrapper ~response =
  structure_to_value_aux
    ~f:(fun x -> [(wrapper, (`Structure x)); (response, (`Structure []))])
